MATCH (d:disease {node_name: 'hereditary breast ovarian cancer syndrome'})
CALL {
  WITH d
  MATCH (d)<-[r:indication]-(drug:drug)
  WHERE r.type = 'indicated'
  RETURN collect(DISTINCT drug.node_name) AS indicated_drugs
}
CALL {
  WITH d
  MATCH (d)<-[r:indication]-(drug:drug)
  WHERE r.type = 'contraindicated'
  RETURN collect(DISTINCT drug.node_name) AS contraindicated_drugs
}
CALL {
  WITH d
  MATCH (d)<-[r:indication]-(drug:drug)
  WHERE r.type = 'off-label'
  RETURN collect(DISTINCT drug.node_name) AS off_label_drugs
}
CALL {
  WITH d
  MATCH (d)-[:disease_phenotype_positive]->(p:effect__phenotype)
  RETURN collect(DISTINCT p.node_name) AS phenotypes
}
CALL {
  WITH d
  MATCH (d)-[:disease_protein]->(g:gene__protein)
  WITH g ORDER BY g.node_name
  RETURN collect(g.node_name)[..10] AS top_10_genes
}
CALL {
  WITH d
  MATCH (d)<-[:exposure_disease]-(e:exposure)
  RETURN collect(DISTINCT e.node_name) AS exposures
}
RETURN indicated_drugs, contraindicated_drugs, off_label_drugs, phenotypes, top_10_genes, exposures

